// Valider et extraire le body de la requête
const body = $input.first().json.body || $input.first().json;
const { candidature_id, user_id, statut, notes } = body;

const STATUTS_VALIDES = ['A envoyer', 'Envoyée', 'Réponse reçue', 'Entretien', 'Offre reçue', 'Refus', 'Abandonnée'];

const errors = [];
if (!candidature_id) errors.push('candidature_id');
if (!user_id) errors.push('user_id');
if (!statut) errors.push('statut');
if (statut && !STATUTS_VALIDES.includes(statut)) errors.push('statut (valeur invalide)');

if (errors.length > 0) {
  return [{
    json: {
      valid: false,
      error: 'VALIDATION_ERROR',
      fields: errors
    }
  }];
}

return [{
  json: {
    valid: true,
    candidature_id,
    user_id,
    statut,
    notes: notes || null
  }
}];

